#include <bits/stdc++.h>
using namespace std;
const int N=2e5+10;
struct Node{
    int ans,qz,hz,sum;
};
int n,a[N];
Node build(int l,int r){
    if(l==r)
        return {a[l],a[l],a[l],a[l]};
    int mid=l+r>>1;
    Node a=build(l,mid),b=build(mid+1,r),t;
    t.ans=max(max(a.ans,b.ans),a.hz+b.qz);
    t.qz=max(a.qz,a.sum+b.qz);
    t.hz=max(b.hz,a.hz+b.sum);
    t.sum=a.sum+b.sum;
    return t;
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    printf("%d",build(1,n).ans);
    return 0;
}
